INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('e e analisa, por via electrónica, o balanço e a demonstração de resultados referentes ao exercício anterior, nomeadamente através da Informação Empresarial Simplificada, apresentados pela empresa junto da entidade competente, no prazo fixado para o efeito nos termos do calendário fiscal. 
