INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' eficácia da recolha de informação, o SIPEP interage para efeitos de mera consulta e recolha nos termos legalmente permitidos com os seguintes sistemas de informação ou bases de dados, para apuramento da existência de eventuais indicações negativas à concessão do passaporte e para verificação dos elementos de identificação do requerente do passaporte:
  a) Sistemas de informação em matéria de fronteiras e estrangeiros, que contenham informação de natureza policial e de cooperação policial internacional, designadamente o Sistema Integrado de Informação da Unidade de Coordenação de Fronteiras e Estrangeiros;
  b) (Revogada.)
  c) Base de dados de identificação civil;
  d) ...
