INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('  4 - Com vista a simplificar o envio dos boletins de alojamento, os estabelecimentos hoteleiros e similares devem proceder ao seu registo junto da Unidade de Coordenação de Fronteiras e Estrangeiros (UCFE) como utilizadores do Sistema de Informação de Boletins de Alojamento, por forma a poderem proceder à respetiva comunicação eletrónica em condições de segurança.
